import{_ as e,o as r,c as h,ah as t}from"./chunks/framework.C2p4DT9L.js";const P=JSON.parse('{"title":"HTTP","description":"","frontmatter":{"title":"HTTP","order":4},"headers":[],"relativePath":"server/network/proto/http.md","filePath":"server/network/proto/http.md"}'),i={name:"server/network/proto/http.md"};function l(n,a,p,o,T,d){return r(),h("div",null,[...a[0]||(a[0]=[t('<h1 id="http-协议" tabindex="-1">HTTP 协议 <a class="header-anchor" href="#http-协议" aria-label="Permalink to “HTTP 协议”">​</a></h1><p>HTTP（Hypertext Transfer Protocol，超文本传输协议）是应用层协议，基于请求-响应模式。HTTP 是互联网的核心协议，用于传输 HTML、图片、视频等资源。</p><h2 id="http-0-9" tabindex="-1">HTTP/0.9 <a class="header-anchor" href="#http-0-9" aria-label="Permalink to “HTTP/0.9”">​</a></h2><p>HTTP/0.9 是 1991 年的版本，只有 GET 方法，只支持 HTML，协议简单。</p><p>请求格式：GET /index.html \\r\\n。</p><p>响应格式：HTML 内容，无响应头。</p><h2 id="http-1-0" tabindex="-1">HTTP/1.0 <a class="header-anchor" href="#http-1-0" aria-label="Permalink to “HTTP/1.0”">​</a></h2><p>HTTP/1.0 是 1996 年的版本，增加多种方法、响应头、状态码。</p><h3 id="方法" tabindex="-1">方法 <a class="header-anchor" href="#方法" aria-label="Permalink to “方法”">​</a></h3><p>GET：请求资源。</p><p>POST：提交数据。</p><p>HEAD：请求响应头，不返回响应体。</p><h3 id="响应头" tabindex="-1">响应头 <a class="header-anchor" href="#响应头" aria-label="Permalink to “响应头”">​</a></h3><p>Content-Type：响应体的类型（text/html、application/json）。</p><p>Content-Length：响应体的长度。</p><p>Date：响应时间。</p><p>Server：服务器信息。</p><h3 id="状态码" tabindex="-1">状态码 <a class="header-anchor" href="#状态码" aria-label="Permalink to “状态码”">​</a></h3><p>200 OK：请求成功。</p><p>301 Moved Permanently：资源永久重定向。</p><p>302 Found：资源临时重定向。</p><p>404 Not Found：资源不存在。</p><p>500 Internal Server Error：服务器内部错误。</p><h3 id="连接" tabindex="-1">连接 <a class="header-anchor" href="#连接" aria-label="Permalink to “连接”">​</a></h3><p>每次请求建立新连接，请求完成后关闭连接。缺点：建立连接开销大，延迟高。</p><h2 id="http-1-1" tabindex="-1">HTTP/1.1 <a class="header-anchor" href="#http-1-1" aria-label="Permalink to “HTTP/1.1”">​</a></h2><p>HTTP/1.1 是 1997 年的版本，增加持久连接、分块传输、缓存控制、更多方法。</p><h3 id="持久连接" tabindex="-1">持久连接 <a class="header-anchor" href="#持久连接" aria-label="Permalink to “持久连接”">​</a></h3><p>Connection: keep-alive 保持连接，多个请求复用同一个连接，减少建立连接的开销。Connection: close 关闭连接。</p><h3 id="分块传输" tabindex="-1">分块传输 <a class="header-anchor" href="#分块传输" aria-label="Permalink to “分块传输”">​</a></h3><p>Transfer-Encoding: chunked 分块传输，响应体大小未知时使用。每个块包含块大小和块数据，最后一个块大小为 0 表示结束。</p><h3 id="缓存控制" tabindex="-1">缓存控制 <a class="header-anchor" href="#缓存控制" aria-label="Permalink to “缓存控制”">​</a></h3><p>Cache-Control：缓存控制策略，如 no-cache（不使用缓存）、max-age=3600（缓存 3600 秒）。</p><p>ETag：资源的唯一标识，用于验证缓存。</p><p>Last-Modified：资源的最后修改时间，用于验证缓存。</p><h3 id="更多方法" tabindex="-1">更多方法 <a class="header-anchor" href="#更多方法" aria-label="Permalink to “更多方法”">​</a></h3><p>PUT：上传资源。</p><p>DELETE：删除资源。</p><p>OPTIONS：查询支持的方法。</p><p>TRACE：回显服务器收到的请求。</p><p>CONNECT：建立隧道，用于 HTTPS 代理。</p><h3 id="host-头" tabindex="-1">Host 头 <a class="header-anchor" href="#host-头" aria-label="Permalink to “Host 头”">​</a></h3><p>Host 头指定请求的主机名，虚拟主机根据 Host 头选择不同的网站。Host 头是 HTTP/1.1 的必选头。</p><h3 id="范围请求" tabindex="-1">范围请求 <a class="header-anchor" href="#范围请求" aria-label="Permalink to “范围请求”">​</a></h3><p>Range: bytes=0-1023 请求资源的部分内容，用于断点续传、视频分片。响应头 Content-Range: bytes 0-1023/ total 表示返回的范围。</p><h2 id="http-2" tabindex="-1">HTTP/2 <a class="header-anchor" href="#http-2" aria-label="Permalink to “HTTP/2”">​</a></h2><p>HTTP/2 是 2015 年的版本，基于 Google 的 SPDY 协议，解决 HTTP/1.1 的性能问题。</p><h3 id="二进制协议" tabindex="-1">二进制协议 <a class="header-anchor" href="#二进制协议" aria-label="Permalink to “二进制协议”">​</a></h3><p>HTTP/1.x 是文本协议，HTTP/2 是二进制协议，解析更高效。</p><h3 id="头部压缩" tabindex="-1">头部压缩 <a class="header-anchor" href="#头部压缩" aria-label="Permalink to “头部压缩”">​</a></h3><p>HPACK 算法压缩头部，减少传输开销。HTTP/1.1 的头部重复多（如 Cookie），占用大量带宽。</p><h3 id="多路复用" tabindex="-1">多路复用 <a class="header-anchor" href="#多路复用" aria-label="Permalink to “多路复用”">​</a></h3><p>一个 TCP 连接可以同时发送多个请求，解决 HTTP/1.1 的队头阻塞问题。请求按流 ID 标识，流可以有优先级。</p><h3 id="服务端推送" tabindex="-1">服务端推送 <a class="header-anchor" href="#服务端推送" aria-label="Permalink to “服务端推送”">​</a></h3><p>服务端可以主动推送资源，减少客户端请求。例如客户端请求 HTML，服务端同时推送 CSS、JS。</p><h3 id="流量控制" tabindex="-1">流量控制 <a class="header-anchor" href="#流量控制" aria-label="Permalink to “流量控制”">​</a></h3><p>基于流的流量控制，窗口大小针对每个流，而不是整个连接。</p><h2 id="http-3" tabindex="-1">HTTP/3 <a class="header-anchor" href="#http-3" aria-label="Permalink to “HTTP/3”">​</a></h2><p>HTTP/3 是 2022 年的版本，基于 QUIC 协议（UDP），解决 HTTP/2 的 TCP 队头阻塞问题。</p><h3 id="quic-协议" tabindex="-1">QUIC 协议 <a class="header-anchor" href="#quic-协议" aria-label="Permalink to “QUIC 协议”">​</a></h3><p>QUIC（Quick UDP Internet Connections）是基于 UDP 的传输协议，提供可靠传输、流量控制、拥塞控制。</p><p>QUIC 的优势：连接建立快（0-RTT）、队头阻塞消除（流独立）、连接迁移（IP 变化不需要重新连接）。</p><h3 id="http-3-的变化" tabindex="-1">HTTP/3 的变化 <a class="header-anchor" href="#http-3-的变化" aria-label="Permalink to “HTTP/3 的变化”">​</a></h3><p>传输层从 TCP 改为 QUIC，保留 HTTP/2 的二进制协议、头部压缩、多路复用。</p><h2 id="https" tabindex="-1">HTTPS <a class="header-anchor" href="#https" aria-label="Permalink to “HTTPS”">​</a></h2><p>HTTPS 是 HTTP over TLS，加密 HTTP 通信，防止窃听、篡改、冒充。</p><h3 id="tls-握手" tabindex="-1">TLS 握手 <a class="header-anchor" href="#tls-握手" aria-label="Permalink to “TLS 握手”">​</a></h3><p>客户端发送 ClientHello，包含支持的加密套件、随机数。</p><p>服务端回复 ServerHello，包含选择的加密套件、随机数、证书。</p><p>服务端发送证书，客户端验证证书。</p><p>客户端生成随机数，用服务端公钥加密，发送给服务端。双方根据三个随机数生成会话密钥。</p><h3 id="https-的性能" tabindex="-1">HTTPS 的性能 <a class="header-anchor" href="#https-的性能" aria-label="Permalink to “HTTPS 的性能”">​</a></h3><p>TLS 握手增加 1-2 个 RTT，连接建立慢。</p><p>TLS 加解密占用 CPU，影响吞吐量。</p><p>优化措施：Session Resumption（会话恢复，减少握手）、TLS 1.3（0-RTT 握手）、硬件加速（加速加解密）。</p><h2 id="http-的性能优化" tabindex="-1">HTTP 的性能优化 <a class="header-anchor" href="#http-的性能优化" aria-label="Permalink to “HTTP 的性能优化”">​</a></h2><h3 id="持久连接-1" tabindex="-1">持久连接 <a class="header-anchor" href="#持久连接-1" aria-label="Permalink to “持久连接”">​</a></h3><p>复用 TCP 连接，减少连接建立的开销。</p><h3 id="域名分片" tabindex="-1">域名分片 <a class="header-anchor" href="#域名分片" aria-label="Permalink to “域名分片”">​</a></h3><p>HTTP/1.1 浏览器对同一域名的连接数有限制（如 6 个），域名分片可以增加连接数。HTTP/2 不需要域名分片。</p><h3 id="资源压缩" tabindex="-1">资源压缩 <a class="header-anchor" href="#资源压缩" aria-label="Permalink to “资源压缩”">​</a></h3><p>gzip、brotli 压缩 HTML、CSS、JS，减少传输数据量。</p><h3 id="缓存" tabindex="-1">缓存 <a class="header-anchor" href="#缓存" aria-label="Permalink to “缓存”">​</a></h3><p>使用 Cache-Control、ETag、Last-Modified 缓存资源，减少请求。</p><h3 id="cdn" tabindex="-1">CDN <a class="header-anchor" href="#cdn" aria-label="Permalink to “CDN”">​</a></h3><p>内容分发网络（CDN）将资源缓存到边缘节点，用户从就近节点获取资源，减少延迟。</p><p>HTTP 是互联网的核心协议，理解 HTTP 的演进和性能优化，有助于构建高性能的 Web 应用。</p>',87)])])}const c=e(i,[["render",l]]);export{P as __pageData,c as default};
